/** Differentially attacks every normalizing proof-law shape with random subtrees. */
@Tag("slow")
class RuleLawFuzzSoakTest {
	@Test
	void threeRowReducedReplayKeepsSetSupport() {
		List<String> names = List.of("v0");
		BindingSetAssignment values = new BindingSetAssignment();
		values.setBindingNames(Set.copyOf(names));
		values.setBindingSets(List.of(
				new ListBindingSet(names, Arrays.asList((Value) null)),
				new ListBindingSet(names, Arrays.asList((Value) null)),
				new ListBindingSet(names, List.of(FuzzVocabulary.S1))));
		EvaluationCase empty = EvaluationCase.builder("empty").build();
		EvaluationOutcome original = new Rdf4jEvaluator().evaluate(new Reduced(values.clone()), empty, 160)
				.getOutcome()
				.orElseThrow();
		EvaluationOutcome candidate = new Rdf4jEvaluator().evaluate(values, empty, 160)
				.getOutcome()
				.orElseThrow();
		System.out.println("[rule-fuzz-replay] original=" + original);
		System.out.println("[rule-fuzz-replay] candidate=" + candidate);
		assertTrue(original.sameAs(candidate, ObservationMode.SET));
	}

	@Test
	void soak() {
		long seed = Long.getLong("equivalence.fuzz.ruleSeed", 20260723L);
		int iterations = Integer.getInteger("equivalence.fuzz.ruleIterations", 20);
		int timeBudgetSeconds = Integer.getInteger("equivalence.fuzz.ruleTimeBudgetSeconds", 120);
		int maxDepth = Integer.getInteger("equivalence.fuzz.ruleMaxDepth", 5);
		int nodeBudget = Integer.getInteger("equivalence.fuzz.ruleNodeBudget", 25);
		boolean edgeOperands = Boolean.parseBoolean(
				System.getProperty("equivalence.fuzz.ruleEdgeOperands", "true"));
		Path artifactDir = Path.of(System.getProperty(
				"equivalence.fuzz.ruleArtifactDir", "target/equivalence-rule-fuzz"));

		List<TreePair> pairs = new RuleLawPairSource(maxDepth, nodeBudget, edgeOperands).pairs(seed, iterations);
		System.out.println("[rule-fuzz] seed=" + seed + " iterations=" + iterations + " pairs=" + pairs.size()
				+ " maxDepth=" + maxDepth + " nodeBudget=" + nodeBudget + " edgeOperands=" + edgeOperands
				+ " timeBudgetSeconds=" + timeBudgetSeconds);

		DifferentialFuzzHarness harness = new DifferentialFuzzHarness(
				FuzzProfile.primary(160),
				FuzzProfile.secondary(160),
				new PairShrinker(),
				new FuzzArtifactWriter(artifactDir, seed),
				true);
		FuzzRunSummary summary = harness.run(seed, pairs, Duration.ofSeconds(timeBudgetSeconds));
		System.out.println(summary.report());

		assertEquals(pairs.size(), summary.pairCount(),
				"time budget truncated the rule-law campaign; raise equivalence.fuzz.ruleTimeBudgetSeconds");
		assertTrue(summary.violations().isEmpty(),
				() -> "rule-law differential violations (artifacts under " + artifactDir + "):\n"
						+ summary.report());
	}
}
